<script setup lang="ts">
import{computed}from"vue";import type{NavigationNode}from"../../router/navigation";import{useLocale}from"../../i18n";
const props=defineProps<{item:NavigationNode;activePage:string;expanded:boolean}>();const emit=defineEmits<{navigate:[name:string];toggle:[id:string]}>();const{t}=useLocale();const active=computed(()=>props.item.routeName===props.activePage||Boolean(props.item.children?.some(child=>child.routeName===props.activePage)));
</script>
<template><div class="nav-node" :class="{active,expanded}"><button class="node-button" :aria-expanded="item.children?expanded:undefined" :aria-current="item.routeName===activePage?'page':undefined" @click="item.children?emit('toggle',item.id):item.routeName&&emit('navigate',item.routeName)"><i>{{item.icon}}</i><span>{{t(item.label)}}</span><b v-if="item.children">⌄</b></button><div v-if="item.children&&expanded" class="children"><button v-for="child in item.children" :key="child.id" :class="{active:child.routeName===activePage}" :aria-current="child.routeName===activePage?'page':undefined" @click="child.routeName&&emit('navigate',child.routeName)"><i>{{child.icon}}</i><span>{{t(child.label)}}</span></button></div></div></template>
<style scoped>.nav-node{display:grid;gap:2px}.node-button,.children button{display:flex;width:100%;align-items:center;gap:11px;border:0;border-radius:9px;background:transparent;color:var(--text-muted);text-align:left;cursor:pointer}.node-button{min-height:42px;padding:0 11px}.node-button:hover,.children button:hover{background:var(--surface-raised);color:var(--text)}.node-button i{display:grid;width:22px;place-items:center;font-size:16px;font-style:normal}.node-button span{flex:1}.node-button b{transition:.18s}.expanded>.node-button b{transform:rotate(180deg)}.active>.node-button{color:var(--accent);font-weight:650}.children{display:grid;gap:2px;padding:2px 0 5px 31px}.children button{position:relative;min-height:34px;padding:0 9px;font-size:11px}.children button i{color:var(--border);font-style:normal}.children button.active{background:var(--accent-soft);color:var(--accent);font-weight:650}.children button.active:before{position:absolute;width:3px;height:17px;left:-8px;border-radius:4px;background:var(--accent);content:""}@media(max-width:860px){.node-button{justify-content:center;padding:0}.node-button span,.node-button b,.children{display:none}}
</style>
